// NEXAI Voice · Verfügbarkeit — toolCallId lesen (flach ODER Vapi-Envelope), 14-Tage-Fenster
const TZ='Europe/Berlin';
const root=$input.first().json||{};
const body=(root.body && typeof root.body==='object')?root.body:root;
let toolCallId='';
if(body && body.message && Array.isArray(body.message.toolCalls) && body.message.toolCalls[0]) toolCallId=body.message.toolCalls[0].id||'';
else toolCallId=body.toolCallId||'';
const now=$now.setZone(TZ);
return [{ json: { toolCallId, windowMinISO: now.toISO(), windowMaxISO: now.plus({days:14}).toISO() } }];

// NEXAI Voice · Verfügbarkeit — Belegt-Liste + heutiges Datum, Antwort im Vapi-results-Format
const TZ='Europe/Berlin';
const now=$now.setZone(TZ);
const WD=['','Mo','Di','Mi','Do','Fr','Sa','So'];
const WDLONG=['','Montag','Dienstag','Mittwoch','Donnerstag','Freitag','Samstag','Sonntag'];
const busy=[];
for(const it of $input.all()){ const e=it.json||{}; if(!e || e.status==='cancelled')continue;
  const s=e.start&&(e.start.dateTime||e.start.date); const en=e.end&&(e.end.dateTime||e.end.date); if(!s||!en)continue;
  const es=DateTime.fromISO(s).setZone(TZ); const ee=DateTime.fromISO(en).setZone(TZ); if(!es.isValid)continue;
  busy.push({es,ee}); }
busy.sort((a,b)=>a.es.toMillis()-b.es.toMillis());
const list=busy.map(b=>WD[b.es.weekday]+' '+b.es.toFormat('dd.LL.')+' '+b.es.toFormat('HH:mm')+'-'+b.ee.toFormat('HH:mm')).join(' | ');
const heute='Heute ist '+WDLONG[now.weekday]+', der '+now.toFormat('dd.LL.yyyy')+'.';
const result=heute+' Belegte Zeiten der nächsten 14 Tage (Wochentag-Kürzel + TT.MM. Uhrzeit, Europe/Berlin): '+(list||'keine')+'. Geschäftszeiten Mo bis Fr 08:00 bis 17:00 Uhr, Termindauer 30 Minuten. WICHTIG: Schlage dem Anrufer im gewünschten Zeitraum GENAU 3 freie Termine an 3 VERSCHIEDENEN Tagen vor (niemals mehrere am selben Tag), chronologisch, die NICHT in der Belegt-Liste stehen. Der Wochentag muss exakt zum Datum passen (nutze die Kürzel aus der Liste). Steht ein Tag nicht in der Liste, ist er komplett frei. Frage danach, welcher Termin passt.';
const toolCallId=$('Parse').first().json.toolCallId;
return [{ json: { results: [{ toolCallId, result }] } }];
